const uint8_t *nc_cjk_glyph(uint32_t cp)
{
    int lo = 0, hi = NC_CJK_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        uint16_t v = s_codes[mid];
        if (v == cp) return &s_bitmaps[mid * NC_CJK_BYTES];
        if (v < cp) lo = mid + 1; else hi = mid - 1;
    }
    return 0;
}
